import numpy as np""" ap = voc_ap(rec, prec, [use_07_metric])Compute VOC AP given precision and recall.If use_07_metric is true, uses theVOC 07 11 point method (default:False).""""""  def voc_ap(rec, prec, use_07_metric=False):    # 针对2007年VOC，使用的11个点计算AP，现在不使用    if use_07_metric:        # 11 point metric        ap = 0.        for t in np.arange(0., 1.1, 0.1):            if np.sum(rec >= t) == 0:                p = 0            else:                p = np.max(prec[rec >= t])            ap = ap + p / 11.    else:        # correct AP calculation        # first append sentinel values at the end        mrec = np.concatenate(([0.], rec, [1.]))  #[0.  0.0666, 0.1333, 0.4   , 0.4666,  1.]         mpre = np.concatenate(([0.], prec, [0.])) #[0.  1.,     0.6666, 0.4285, 0.3043,  0.]        # compute the precision envelope        # 计算出precision的各个断点(折线点)        for i in range(mpre.size - 1, 0, -1):            mpre[i - 1] = np.maximum(mpre[i - 1], mpre[i])  #[1.     1.     0.6666 0.4285 0.3043 0.    ]        # to calculate area under PR curve, look for points        # where X axis (recall) changes value        i = np.where(mrec[1:] != mrec[:-1])[0]  #precision前后两个值不一样的点        print(mrec[1:], mrec[:-1])        print(i) #[0, 1, 3, 4, 5]        # AP= AP1 + AP2+ AP3+ AP4        ap = np.sum((mrec[i + 1] - mrec[i]) * mpre[i + 1])    return aprec = np.array([0.0666, 0.1333,0.1333, 0.4, 0.4666])prec = np.array([1., 0.6666, 0.6666, 0.4285, 0.3043])rec = np.array([0.0,0.0])prec = np.array([1.0,1.0])ap = voc_ap(rec, prec)print(ap) #输出：0.2456"""def calculate_iou(bb1, bb2):    # Calculate the intersection over union (IoU) between two bounding boxes    x1 = max(bb1[0], bb2[0])    y1 = max(bb1[1], bb2[1])    x2 = min(bb1[2], bb2[2])    y2 = min(bb1[3], bb2[3])        intersection_area = max(0, x2 - x1 + 1) * max(0, y2 - y1 + 1)    bb1_area = (bb1[2] - bb1[0] + 1) * (bb1[3] - bb1[1] + 1)    bb2_area = (bb2[2] - bb2[0] + 1) * (bb2[3] - bb2[1] + 1)        iou = intersection_area / float(bb1_area + bb2_area - intersection_area)    return ioudef calculate_recall_precision(gt_bbxs, detection_bbxs, iou_threshold=0.5):    true_positives = 0    false_positives = 0    total_positives = len(gt_bbxs)    for gt_bbx in gt_bbxs:        gt_bbox = gt_bbx[2:6]        matched_detection = None        max_iou = 0        for dt_bbx in detection_bbxs:            dt_bbox = dt_bbx[2:6]            iou = calculate_iou(gt_bbox, dt_bbox)            if iou > max_iou:                max_iou = iou                matched_detection = dt_bbx                print(matched_detection)        if matched_detection and max_iou >= iou_threshold:            true_positives += 1        else:            false_positives += 1    print(false_positives)    print(true_positives)    recall = true_positives / total_positives if total_positives > 0 else 0    precision = true_positives / (true_positives + false_positives) if (true_positives + false_positives) > 0 else 0    return recall, precision# Example GT bounding boxes [vid, x, y, yaw, l, w]gt_bbxs = [    [1, 0, 0, 0, 2.0, 1.5],    [2, 1, 1, 0, 1.5, 1.0],    [3, 2, 2, 0, 1.2, 0.8]]# Example detection bounding boxes [vid, x, y, yaw, l, w]detection_bbxs = [    [1, 0.1, 0.1, 0, 2.1, 1.6],    [2, 1.2, 0.8, 0, 1.6, 0.9],    [1, 0.2, 0.2, 0, 1.8, 1.3],    [3, 2.1, 2.0, 0, 1.3, 0.7]]gt_bbxs = [    [1, 0, 0, 0, 2.0, 1.5],]# Example detection bounding boxes [vid, x, y, yaw, l, w]detection_bbxs = [    [1, 0.1, 0.1, 0, 2.1, 1.6],    [1, 0.2, 0.2, 0, 1.8, 1.3],]iou_threshold = 0.5recall, precision = calculate_recall_precision(gt_bbxs, detection_bbxs, iou_threshold)print("Recall:", recall)print("Precision:", precision)